import * as fs from "fs";
import * as path from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const LESSONS_DIR = path.join(__dirname, "../client/src/data/lessons");

interface LessonData {
  title: string;
  cellular: { title: string; content: string };
  riskFactors: string[];
  diagnostics: string[];
  management: string[];
  nursingActions: string[];
  assessmentFindings: string[];
  signs: { left: string[]; right: string[] };
  medications: { name: string; type: string; action: string; sideEffects: string; contra: string; pearl: string }[];
  pearls: string[];
  lifespan?: { title: string; content: string };
  quiz: { question: string; options: string[]; correct: number; rationale: string }[];
}

function escapeStr(s: string): string {
  return s.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n");
}

function buildLessonString(lesson: LessonData): string {
  const lines: string[] = [];
  lines.push(`    title: "${escapeStr(lesson.title)}",`);
  lines.push(`    cellular: { title: "${escapeStr(lesson.cellular.title)}", content: "${escapeStr(lesson.cellular.content)}" },`);
  lines.push(`    riskFactors: [${lesson.riskFactors.map(r => `"${escapeStr(r)}"`).join(",")}],`);
  lines.push(`    diagnostics: [${lesson.diagnostics.map(r => `"${escapeStr(r)}"`).join(",")}],`);
  lines.push(`    management: [${lesson.management.map(r => `"${escapeStr(r)}"`).join(",")}],`);
  lines.push(`    nursingActions: [${lesson.nursingActions.map(r => `"${escapeStr(r)}"`).join(",")}],`);
  lines.push(`    assessmentFindings: [${lesson.assessmentFindings.map(r => `"${escapeStr(r)}"`).join(",")}],`);
  lines.push(`    signs: {`);
  lines.push(`      left: [${lesson.signs.left.map(r => `"${escapeStr(r)}"`).join(",")}],`);
  lines.push(`      right: [${lesson.signs.right.map(r => `"${escapeStr(r)}"`).join(",")}]`);
  lines.push(`    },`);
  lines.push(`    medications: [${lesson.medications.map(m =>
    `{\n      name: "${escapeStr(m.name)}",\n      type: "${escapeStr(m.type)}",\n      action: "${escapeStr(m.action)}",\n      sideEffects: "${escapeStr(m.sideEffects)}",\n      contra: "${escapeStr(m.contra)}",\n      pearl: "${escapeStr(m.pearl)}"\n    }`
  ).join(",")}],`);
  lines.push(`    pearls: [${lesson.pearls.map(r => `"${escapeStr(r)}"`).join(",")}],`);
  if (lesson.lifespan) {
    lines.push(`    lifespan: { title: "${escapeStr(lesson.lifespan.title)}", content: "${escapeStr(lesson.lifespan.content)}" },`);
  }
  lines.push(`    quiz: [${lesson.quiz.map(q =>
    `{\n        question: "${escapeStr(q.question)}",\n        options: [${q.options.map(o => `"${escapeStr(o)}"`).join(",")}],\n        correct: ${q.correct},\n        rationale: "${escapeStr(q.rationale)}"\n      }`
  ).join(",\n      ")}]`);
  return lines.join("\n    ");
}

function injectLesson(lessonId: string, lesson: LessonData): boolean {
  const files = fs.readdirSync(LESSONS_DIR).filter(f => f.endsWith(".ts") && f !== "index.ts" && f !== "types.ts");
  
  for (const file of files) {
    const filePath = path.join(LESSONS_DIR, file);
    let content = fs.readFileSync(filePath, "utf8");
    const marker = `"${lessonId}":`;
    const idx = content.indexOf(marker);
    if (idx === -1) continue;
    
    const slice = content.slice(idx, idx + 200);
    if (!slice.includes("[WRITE YOUR")) continue;
    
    let braceCount = 0;
    let entryStart = idx + marker.length;
    while (entryStart < content.length && content[entryStart] !== "{") entryStart++;
    let entryEnd = entryStart;
    for (let i = entryStart; i < content.length; i++) {
      if (content[i] === "{") braceCount++;
      if (content[i] === "}") {
        braceCount--;
        if (braceCount === 0) {
          entryEnd = i + 1;
          break;
        }
      }
    }
    
    const newEntry = `{\n    ${buildLessonString(lesson)}\n  }`;
    content = content.slice(0, entryStart) + newEntry + content.slice(entryEnd);
    fs.writeFileSync(filePath, content);
    console.log(`Injected: ${lessonId} -> ${file}`);
    return true;
  }
  
  console.log(`NOT FOUND: ${lessonId}`);
  return false;
}

